/* ─── The LogoStack Component ─── */
export function LogoStack() {
  const [queue, setQueue] = useState<number[]>(() =>
    LOGOS.map((_, i) => i)
  );

  useEffect(() => {
    const timer = setInterval(() => {
      setQueue((prev) => {
        const next = [...prev];
        const first = next.shift()!;
        next.push(first);
        return next;
      });
    }, ROTATE_MS);
    return () => clearInterval(timer);
  }, []);

  const visible = queue.slice(0, VISIBLE_COUNT);

  return (
    <motion.div
      initial={{ opacity: 0, y: 12 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.8, delay: 0.05, ease: [0.25, 0.46, 0.45, 0.94] }}
      className="flex flex-col items-center pb-10"
      aria-label="Logos of companies and institutions our mentors come from"
    >
      {/* Stack container */}
      <div
        className="relative"
        style={{
          width: CARD_SIZE,
          height: CARD_SIZE + 40,
        }}
      >
        <AnimatePresence initial={false}>
          {visible.map((logoIndex, stackPos) => {
            const logo = LOGOS[logoIndex];
            const pos = STACK[stackPos];

            return (
              <motion.div
                key={logo.name}
                className="absolute left-0 flex items-center justify-center overflow-visible"
                style={{
                  width: CARD_SIZE,
                  height: CARD_SIZE,
                  bottom: 0,
                  backgroundColor: logo.bg,
                  borderRadius: 26,
                  border: logo.border || "1px solid rgba(255,255,255,0.12)",
                  boxShadow:
                    "0 8px 32px rgba(0,0,0,0.12), 0 2px 8px rgba(0,0,0,0.06)",
                  transformOrigin: "center bottom",
                }}
                initial={{
                  y: -38,
                  scale: 0.6,
                  opacity: 0,
                }}
                animate={{
                  y: pos.y,
                  scale: pos.scale,
                  opacity: pos.opacity,
                  zIndex: pos.zIndex,
                  filter:
                    stackPos >= 2
                      ? `blur(${stackPos === 2 ? 0.5 : 1}px)`
                      : "blur(0px)",
                }}
                exit={{
                  y: 8,
                  scale: 0.95,
                  opacity: 0,
                }}
                transition={{
                  y: {
                    type: "spring",
                    stiffness: 180,
                    damping: 22,
                    mass: 0.8,
                  },
                  scale: {
                    type: "spring",
                    stiffness: 180,
                    damping: 22,
                    mass: 0.8,
                  },
                  opacity: {
                    duration: 0.45,
                    ease: "easeInOut",
                  },
                  filter: {
                    duration: 0.4,
                    ease: "easeInOut",
                  },
                  zIndex: {
                    duration: 0,
                  },
                }}
              >
                {logo.icon}
              </motion.div>
            );
          })}
        </AnimatePresence>
      </div>
    </motion.div>
  );
}